# solution.py
"""TeamSyncPro - a business collaboration and project management core.

This module implements ``TeamCollaborationManager``, an in-memory, thread-safe
domain core for a project management product.  It bundles together the entities
and services a business collaboration tool needs:

* User management with role based access control primitives.
* Project and task management with assignment indexing.
* Threaded messaging with file attachments.
* A performance dashboard (completion rates, durations, peer ratings).
* A reporting module able to export to CSV and PDF.

The implementation favours correctness, isolation (callers never receive a
reference to internal state), and safe concurrent access through a single
shared re-entrant lock that is shared by every sub-manager.

Standard library only.
"""

from __future__ import annotations

import copy
import csv
import enum
import io
import threading
from collections import defaultdict
from dataclasses import dataclass, field
from datetime import datetime
from typing import Dict, List, Optional, Set


# ---------------------------------------------------------------------------
# Enumerations
# ---------------------------------------------------------------------------
class TaskStatus(enum.Enum):
    """Lifecycle states for a task."""

    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class UserRole(enum.Enum):
    """Role based access control roles."""

    ADMIN = "admin"
    MANAGER = "manager"
    MEMBER = "member"
    VIEWER = "viewer"


class ReportFormat(enum.Enum):
    """Supported export formats for reports."""

    CSV = "csv"
    PDF = "pdf"


class ReportType(enum.Enum):
    """Kinds of report the reporting module can produce."""

    PROJECT_PROGRESS = "project_progress"
    TEAM_PERFORMANCE = "team_performance"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Exception hierarchy
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    """Base class for every error raised by the manager."""


class ValidationError(TeamCollaborationError):
    """Raised when input fails validation."""


class NotFoundError(TeamCollaborationError):
    """Raised when a referenced entity does not exist."""


class AuthorizationError(TeamCollaborationError):
    """Raised when an actor is not permitted to perform an action."""


class DuplicateError(TeamCollaborationError):
    """Raised when a uniqueness constraint is violated."""


class ConflictError(TeamCollaborationError):
    """Raised when an operation conflicts with current state."""


# ---------------------------------------------------------------------------
# Domain models
# ---------------------------------------------------------------------------
@dataclass
class Attachment:
    """A file attached to a message."""

    filename: str
    size: int
    uploaded_by: int
    uploaded_at: datetime


@dataclass
class User:
    """A member of the organization."""

    id: int
    username: str
    email: str
    role: UserRole
    created_at: datetime


@dataclass
class Project:
    """A project owned by a user."""

    id: int
    name: str
    description: str
    start_date: datetime
    end_date: datetime
    owner_id: int
    created_at: datetime


@dataclass
class Task:
    """A unit of work belonging to a project."""

    id: int
    project_id: int
    title: str
    status: TaskStatus
    assignee_id: Optional[int]
    deadline: Optional[datetime]
    started_at: Optional[datetime]
    completed_at: Optional[datetime]
    created_at: datetime
    description: str = ""


@dataclass
class Message:
    """A communication entry attached to a project or a task."""

    id: int
    author_id: int
    body: str
    project_id: Optional[int]
    task_id: Optional[int]
    parent_id: Optional[int]
    created_at: datetime
    edited_at: Optional[datetime] = None
    attachments: List[Attachment] = field(default_factory=list)


@dataclass
class Rating:
    """A peer rating left for a user."""

    id: int
    rater_id: int
    ratee_id: int
    score: int
    feedback: str
    task_id: Optional[int]
    created_at: datetime


# ---------------------------------------------------------------------------
# Shared state
# ---------------------------------------------------------------------------
class _State:
    """Container for all shared collections, the id sequence and the lock.

    A single ``RLock`` is created here and reused by every sub-manager so that
    cross-entity operations (for example deleting a project and cascading to
    its tasks and messages) remain atomic.
    """

    def __init__(self, now):
        self.now = now if now is not None else datetime.now
        self.lock = threading.RLock()

        self.users: Dict[int, User] = {}
        self.projects: Dict[int, Project] = {}
        self.tasks: Dict[int, Task] = {}
        self.messages: Dict[int, Message] = {}
        self.ratings: Dict[int, Rating] = {}

        # user_id -> set of task ids assigned to that user
        self.assignee_index: Dict[int, Set[int]] = defaultdict(set)

        self._id_seq = 0

    def next_id(self) -> int:
        """Return the next globally unique identifier (starting at 1)."""

        self._id_seq += 1
        return self._id_seq


def _clone(obj):
    """Return a deep copy so callers can never mutate internal state."""

    return copy.deepcopy(obj)


# ---------------------------------------------------------------------------
# Base component
# ---------------------------------------------------------------------------
class _Component:
    """Common helpers shared by every sub-manager."""

    def __init__(self, state: _State):
        self._state = state
        # Exposed so that ``manager.users._lock is manager._lock`` etc.
        self._lock = state.lock

    # -- existence helpers --------------------------------------------------
    def _require_user(self, user_id: int) -> User:
        user = self._state.users.get(user_id)
        if user is None:
            raise NotFoundError("user {0} not found".format(user_id))
        return user

    def _require_project(self, project_id: int) -> Project:
        project = self._state.projects.get(project_id)
        if project is None:
            raise NotFoundError("project {0} not found".format(project_id))
        return project

    def _require_task(self, task_id: int) -> Task:
        task = self._state.tasks.get(task_id)
        if task is None:
            raise NotFoundError("task {0} not found".format(task_id))
        return task

    def _require_message(self, message_id: int) -> Message:
        message = self._state.messages.get(message_id)
        if message is None:
            raise NotFoundError("message {0} not found".format(message_id))
        return message


# ---------------------------------------------------------------------------
# User management
# ---------------------------------------------------------------------------
class _UserManager(_Component):
    def register_user(self, username, email, role=UserRole.MEMBER) -> User:
        with self._lock:
            self._validate_username(username)
            self._validate_email(email)
            if not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")
            self._ensure_unique_username(username, exclude_id=None)
            self._ensure_unique_email(email, exclude_id=None)

            user = User(
                id=self._state.next_id(),
                username=username,
                email=email,
                role=role,
                created_at=self._state.now(),
            )
            self._state.users[user.id] = user
            return _clone(user)

    def get_user(self, user_id) -> User:
        with self._lock:
            return _clone(self._require_user(user_id))

    def list_users(self) -> List[User]:
        with self._lock:
            return [
                _clone(self._state.users[uid])
                for uid in sorted(self._state.users)
            ]

    def update_user(self, user_id, username=None, email=None, role=None) -> User:
        with self._lock:
            user = self._require_user(user_id)

            if username is not None:
                self._validate_username(username)
                self._ensure_unique_username(username, exclude_id=user_id)

            if email is not None:
                self._validate_email(email)
                self._ensure_unique_email(email, exclude_id=user_id)

            if role is not None and not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")

            if username is not None:
                user.username = username
            if email is not None:
                user.email = email
            if role is not None:
                user.role = role
            return _clone(user)

    def delete_user(self, user_id) -> None:
        with self._lock:
            self._require_user(user_id)

            for project in self._state.projects.values():
                if project.owner_id == user_id:
                    raise ConflictError(
                        "user {0} owns a project".format(user_id)
                    )

            for task_id in self._state.assignee_index.get(user_id, set()):
                task = self._state.tasks.get(task_id)
                if task is not None and task.status != TaskStatus.COMPLETED:
                    raise ConflictError(
                        "user {0} has open tasks".format(user_id)
                    )

            self._state.assignee_index.pop(user_id, None)
            del self._state.users[user_id]

    # -- validation helpers -------------------------------------------------
    @staticmethod
    def _validate_username(username) -> None:
        if not isinstance(username, str) or not username.strip():
            raise ValidationError("username must be a non-empty string")

    @staticmethod
    def _validate_email(email) -> None:
        if not isinstance(email, str) or not email.strip() or "@" not in email:
            raise ValidationError("email must contain '@'")

    def _ensure_unique_username(self, username, exclude_id) -> None:
        for uid, user in self._state.users.items():
            if uid != exclude_id and user.username == username:
                raise DuplicateError(
                    "username {0!r} already exists".format(username)
                )

    def _ensure_unique_email(self, email, exclude_id) -> None:
        for uid, user in self._state.users.items():
            if uid != exclude_id and user.email == email:
                raise DuplicateError(
                    "email {0!r} already exists".format(email)
                )


# ---------------------------------------------------------------------------
# Project management
# ---------------------------------------------------------------------------
class _ProjectManager(_Component):
    def create_project(
        self, name, start_date, end_date, owner_id, description=""
    ) -> Project:
        with self._lock:
            if not isinstance(name, str) or not name.strip():
                raise ValidationError("project name must be non-empty")
            if end_date < start_date:
                raise ValidationError("end_date must not be before start_date")
            self._require_user(owner_id)

            project = Project(
                id=self._state.next_id(),
                name=name,
                description=description or "",
                start_date=start_date,
                end_date=end_date,
                owner_id=owner_id,
                created_at=self._state.now(),
            )
            self._state.projects[project.id] = project
            return _clone(project)

    def get_project(self, project_id) -> Project:
        with self._lock:
            return _clone(self._require_project(project_id))

    def list_projects(self) -> List[Project]:
        with self._lock:
            return [
                _clone(self._state.projects[pid])
                for pid in sorted(self._state.projects)
            ]

    def update_project(
        self, project_id, name=None, start_date=None, end_date=None,
        description=None,
    ) -> Project:
        with self._lock:
            project = self._require_project(project_id)

            if name is not None and (not isinstance(name, str) or not name.strip()):
                raise ValidationError("project name must be non-empty")

            new_start = start_date if start_date is not None else project.start_date
            new_end = end_date if end_date is not None else project.end_date
            if new_end < new_start:
                raise ValidationError("end_date must not be before start_date")

            if name is not None:
                project.name = name
            if start_date is not None:
                project.start_date = start_date
            if end_date is not None:
                project.end_date = end_date
            if description is not None:
                project.description = description
            return _clone(project)

    def delete_project(self, project_id) -> None:
        with self._lock:
            self._require_project(project_id)

            task_ids = [
                tid for tid, task in self._state.tasks.items()
                if task.project_id == project_id
            ]
            for tid in task_ids:
                task = self._state.tasks.pop(tid)
                if task.assignee_id is not None:
                    self._state.assignee_index.get(
                        task.assignee_id, set()
                    ).discard(tid)

            doomed_tasks = set(task_ids)
            message_ids = [
                mid for mid, msg in self._state.messages.items()
                if msg.project_id == project_id or msg.task_id in doomed_tasks
            ]
            for mid in message_ids:
                del self._state.messages[mid]

            del self._state.projects[project_id]


# ---------------------------------------------------------------------------
# Task management
# ---------------------------------------------------------------------------
class _TaskManager(_Component):
    def create_task(
        self, project_id, title, assignee_id=None, deadline=None
    ) -> Task:
        with self._lock:
            project = self._require_project(project_id)
            if not isinstance(title, str) or not title.strip():
                raise ValidationError("task title must be non-empty")
            if assignee_id is not None:
                self._require_user(assignee_id)
            if deadline is not None and deadline < project.start_date:
                raise ValidationError("deadline before project start")

            task = Task(
                id=self._state.next_id(),
                project_id=project_id,
                title=title,
                status=TaskStatus.NOT_STARTED,
                assignee_id=assignee_id,
                deadline=deadline,
                started_at=None,
                completed_at=None,
                created_at=self._state.now(),
            )
            self._state.tasks[task.id] = task
            if assignee_id is not None:
                self._state.assignee_index[assignee_id].add(task.id)
            return _clone(task)

    def get_task(self, task_id) -> Task:
        with self._lock:
            return _clone(self._require_task(task_id))

    def list_tasks_by_project(self, project_id) -> List[Task]:
        with self._lock:
            self._require_project(project_id)
            tasks = [
                task for task in self._state.tasks.values()
                if task.project_id == project_id
            ]
            tasks.sort(key=lambda t: t.id)
            return [_clone(task) for task in tasks]

    def list_tasks_by_assignee(self, user_id) -> List[Task]:
        with self._lock:
            self._require_user(user_id)
            task_ids = sorted(self._state.assignee_index.get(user_id, set()))
            return [_clone(self._state.tasks[tid]) for tid in task_ids]

    def assign_task(self, task_id, assignee_id) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            self._require_user(assignee_id)
            self._move_assignment(task, assignee_id)
            return _clone(task)

    def reassign_task(self, task_id, new_assignee_id) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            self._require_user(new_assignee_id)
            self._move_assignment(task, new_assignee_id)
            return _clone(task)

    def unassign_task(self, task_id) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            self._move_assignment(task, None)
            return _clone(task)

    def set_deadline(self, task_id, deadline) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            if deadline is not None:
                project = self._state.projects.get(task.project_id)
                if project is not None and deadline < project.start_date:
                    raise ValidationError("deadline before project start")
            task.deadline = deadline
            return _clone(task)

    def update_status(self, task_id, status) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            if not isinstance(status, TaskStatus):
                raise ValidationError("status must be a TaskStatus")

            now = self._state.now()
            if status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now
            elif status == TaskStatus.NOT_STARTED:
                task.started_at = None
                task.completed_at = None

            task.status = status
            return _clone(task)

    # -- helpers ------------------------------------------------------------
    def _move_assignment(self, task: Task, new_assignee_id: Optional[int]) -> None:
        if task.assignee_id is not None:
            self._state.assignee_index.get(task.assignee_id, set()).discard(task.id)
        task.assignee_id = new_assignee_id
        if new_assignee_id is not None:
            self._state.assignee_index[new_assignee_id].add(task.id)


# ---------------------------------------------------------------------------
# Messaging
# ---------------------------------------------------------------------------
class _MessageManager(_Component):
    def post_message(
        self, author_id, body, project_id=None, task_id=None,
        attachments=None, parent_id=None,
    ) -> Message:
        with self._lock:
            self._require_user(author_id)

            if (project_id is None) == (task_id is None):
                raise ValidationError(
                    "exactly one of project_id or task_id is required"
                )

            if project_id is not None:
                self._require_project(project_id)
            else:
                self._require_task(task_id)

            attachment_specs = attachments or []
            if not body and not attachment_specs:
                raise ValidationError("message needs a body or an attachment")

            if parent_id is not None:
                self._require_message(parent_id)

            built = self._build_attachments(attachment_specs, author_id)

            message = Message(
                id=self._state.next_id(),
                author_id=author_id,
                body=body,
                project_id=project_id,
                task_id=task_id,
                parent_id=parent_id,
                created_at=self._state.now(),
                edited_at=None,
                attachments=built,
            )
            self._state.messages[message.id] = message
            return _clone(message)

    def edit_message(self, message_id, author_id, body) -> Message:
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != author_id:
                raise AuthorizationError("only the author may edit a message")
            if not body:
                raise ValidationError("message body must be non-empty")
            message.body = body
            message.edited_at = self._state.now()
            return _clone(message)

    def add_attachment(self, message_id, author_id, filename, data) -> Message:
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != author_id:
                raise AuthorizationError(
                    "only the author may add an attachment"
                )
            if not isinstance(filename, str) or not filename.strip():
                raise ValidationError("filename must be non-empty")
            message.attachments.append(
                self._build_attachment(filename, data, author_id)
            )
            return _clone(message)

    def list_messages_by_project(self, project_id) -> List[Message]:
        with self._lock:
            self._require_project(project_id)
            messages = [
                msg for msg in self._state.messages.values()
                if msg.project_id == project_id
            ]
            messages.sort(key=lambda m: m.id)
            return [_clone(msg) for msg in messages]

    def list_messages_by_task(self, task_id) -> List[Message]:
        with self._lock:
            self._require_task(task_id)
            messages = [
                msg for msg in self._state.messages.values()
                if msg.task_id == task_id
            ]
            messages.sort(key=lambda m: m.id)
            return [_clone(msg) for msg in messages]

    def delete_message(self, message_id, author_id) -> None:
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != author_id:
                raise AuthorizationError(
                    "only the author may delete a message"
                )
            del self._state.messages[message_id]

    # -- helpers ------------------------------------------------------------
    def _build_attachments(self, specs, author_id) -> List[Attachment]:
        built = []
        for spec in specs:
            if isinstance(spec, Attachment):
                built.append(spec)
            else:
                filename, data = spec
                built.append(self._build_attachment(filename, data, author_id))
        return built

    def _build_attachment(self, filename, data, author_id) -> Attachment:
        size = len(data) if data is not None else 0
        return Attachment(
            filename=filename,
            size=size,
            uploaded_by=author_id,
            uploaded_at=self._state.now(),
        )


# ---------------------------------------------------------------------------
# Performance dashboard
# ---------------------------------------------------------------------------
class _PerformanceManager(_Component):
    def get_completion_rate(self, user_id) -> float:
        with self._lock:
            self._require_user(user_id)
            tasks = self._assigned_tasks(user_id)
            if not tasks:
                return 0.0
            completed = sum(
                1 for t in tasks if t.status == TaskStatus.COMPLETED
            )
            return completed / len(tasks)

    def get_average_completion_time(self, user_id) -> Optional[float]:
        with self._lock:
            self._require_user(user_id)
            durations = self._completion_durations(self._assigned_tasks(user_id))
            if not durations:
                return None
            return sum(durations) / len(durations)

    def submit_rating(
        self, rater_id, ratee_id, score, feedback="", task_id=None
    ) -> Rating:
        with self._lock:
            self._require_user(rater_id)
            self._require_user(ratee_id)
            if rater_id == ratee_id:
                raise ConflictError("a user cannot rate themselves")
            if not isinstance(score, int) or isinstance(score, bool) or not (1 <= score <= 5):
                raise ValidationError("score must be an integer in 1..5")
            if task_id is not None:
                self._require_task(task_id)

            rating = Rating(
                id=self._state.next_id(),
                rater_id=rater_id,
                ratee_id=ratee_id,
                score=score,
                feedback=feedback or "",
                task_id=task_id,
                created_at=self._state.now(),
            )
            self._state.ratings[rating.id] = rating
            return _clone(rating)

    def get_ratings_summary(self, user_id) -> dict:
        with self._lock:
            self._require_user(user_id)
            ratings = sorted(
                (r for r in self._state.ratings.values() if r.ratee_id == user_id),
                key=lambda r: r.id,
            )
            count = len(ratings)
            average = sum(r.score for r in ratings) / count if count else 0.0
            return {
                "user_id": user_id,
                "count": count,
                "average": average,
                "ratings": [_clone(r) for r in ratings],
            }

    def get_user_dashboard(self, user_id) -> dict:
        with self._lock:
            self._require_user(user_id)
            tasks = self._assigned_tasks(user_id)
            total = len(tasks)
            completed = sum(
                1 for t in tasks if t.status == TaskStatus.COMPLETED
            )
            in_progress = sum(
                1 for t in tasks if t.status == TaskStatus.IN_PROGRESS
            )
            not_started = sum(
                1 for t in tasks if t.status == TaskStatus.NOT_STARTED
            )
            durations = self._completion_durations(tasks)
            avg_time = (
                sum(durations) / len(durations) if durations else None
            )
            scores = [
                r.score for r in self._state.ratings.values()
                if r.ratee_id == user_id
            ]
            rating_count = len(scores)
            rating_average = (
                sum(scores) / rating_count if rating_count else 0.0
            )
            return {
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": completed / total if total else 0.0,
                "average_completion_time": avg_time,
                "rating_count": rating_count,
                "rating_average": rating_average,
            }

    # -- helpers ------------------------------------------------------------
    def _assigned_tasks(self, user_id) -> List[Task]:
        return [
            self._state.tasks[tid]
            for tid in self._state.assignee_index.get(user_id, set())
            if tid in self._state.tasks
        ]

    @staticmethod
    def _completion_durations(tasks) -> List[float]:
        durations = []
        for task in tasks:
            if (
                task.status == TaskStatus.COMPLETED
                and task.started_at is not None
                and task.completed_at is not None
            ):
                durations.append(
                    (task.completed_at - task.started_at).total_seconds()
                )
        return durations


# ---------------------------------------------------------------------------
# Reporting
# ---------------------------------------------------------------------------
class _ReportManager(_Component):
    def project_progress_report(self, project_id) -> dict:
        with self._lock:
            project = self._require_project(project_id)
            tasks = [
                t for t in self._state.tasks.values()
                if t.project_id == project_id
            ]
            total = len(tasks)
            status_counts = {status.value: 0 for status in TaskStatus}
            for task in tasks:
                status_counts[task.status.value] += 1
            completed = status_counts[TaskStatus.COMPLETED.value]
            now = self._state.now()
            overdue = sum(
                1 for t in tasks
                if t.deadline is not None
                and t.deadline < now
                and t.status != TaskStatus.COMPLETED
            )

            per_assignee = {}
            groups = defaultdict(list)
            for task in tasks:
                if task.assignee_id is not None:
                    groups[task.assignee_id].append(task)
            for uid, group in groups.items():
                g_total = len(group)
                g_done = sum(
                    1 for t in group if t.status == TaskStatus.COMPLETED
                )
                per_assignee[uid] = {
                    "total_tasks": g_total,
                    "completed_tasks": g_done,
                    "completion_rate": g_done / g_total if g_total else 0.0,
                }

            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project_id,
                "project_name": project.name,
                "total_tasks": total,
                "status_counts": status_counts,
                "completion_rate": completed / total if total else 0.0,
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
            }

    def team_performance_report(self, project_id=None) -> dict:
        with self._lock:
            if project_id is not None:
                self._require_project(project_id)
                tasks = [
                    t for t in self._state.tasks.values()
                    if t.project_id == project_id
                ]
            else:
                tasks = list(self._state.tasks.values())

            groups = defaultdict(list)
            for task in tasks:
                if (
                    task.assignee_id is not None
                    and task.assignee_id in self._state.users
                ):
                    groups[task.assignee_id].append(task)

            rows = []
            for uid in sorted(groups):
                rows.append(self._performance_row(uid, groups[uid]))

            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "scope_project_id": project_id,
                "rows": rows,
            }

    def individual_performance_report(self, user_id) -> dict:
        with self._lock:
            self._require_user(user_id)
            tasks = sorted(
                (
                    self._state.tasks[tid]
                    for tid in self._state.assignee_index.get(user_id, set())
                    if tid in self._state.tasks
                ),
                key=lambda t: t.id,
            )
            row = self._performance_row(user_id, tasks)
            counts = {status.value: 0 for status in TaskStatus}
            for task in tasks:
                counts[task.status.value] += 1

            row.update(
                {
                    "report_type": ReportType.INDIVIDUAL_PERFORMANCE.value,
                    "in_progress_tasks": counts[TaskStatus.IN_PROGRESS.value],
                    "not_started_tasks": counts[TaskStatus.NOT_STARTED.value],
                    "tasks": [
                        {
                            "task_id": t.id,
                            "project_id": t.project_id,
                            "title": t.title,
                            "status": t.status.value,
                        }
                        for t in tasks
                    ],
                }
            )
            return row

    def export_report(self, report, fmt) -> object:
        with self._lock:
            if not isinstance(report, dict):
                raise ValidationError("report must be a dict")
            if not isinstance(fmt, ReportFormat):
                raise ValidationError("fmt must be a ReportFormat")
            if fmt == ReportFormat.CSV:
                return self._to_csv(report)
            return self._to_pdf(report)

    # -- helpers ------------------------------------------------------------
    def _performance_row(self, user_id, tasks) -> dict:
        total = len(tasks)
        completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
        durations = _PerformanceManager._completion_durations(tasks)
        avg_time = sum(durations) / len(durations) if durations else None
        scores = [
            r.score for r in self._state.ratings.values()
            if r.ratee_id == user_id
        ]
        rating_count = len(scores)
        rating_average = sum(scores) / rating_count if rating_count else 0.0
        user = self._state.users.get(user_id)
        return {
            "user_id": user_id,
            "username": user.username if user is not None else "",
            "total_tasks": total,
            "completed_tasks": completed,
            "completion_rate": completed / total if total else 0.0,
            "average_completion_time": avg_time,
            "rating_count": rating_count,
            "rating_average": rating_average,
        }

    @staticmethod
    def _stringify(value) -> str:
        if isinstance(value, dict):
            return "; ".join(
                "{0}={1}".format(k, value[k]) for k in value
            )
        if isinstance(value, (list, tuple)):
            return "; ".join(str(item) for item in value)
        return "" if value is None else str(value)

    @classmethod
    def _to_csv(cls, report) -> str:
        out = io.StringIO()
        writer = csv.writer(out)
        rows = report.get("rows")
        if isinstance(rows, list):
            if rows:
                header = list(rows[0].keys())
            else:
                header = [
                    "user_id", "username", "total_tasks",
                    "completed_tasks", "completion_rate",
                ]
            writer.writerow(header)
            for row in rows:
                writer.writerow([cls._stringify(row.get(col)) for col in header])
        else:
            writer.writerow(["metric", "value"])
            for key, value in report.items():
                writer.writerow([key, cls._stringify(value)])
        return out.getvalue()

    @classmethod
    def _to_pdf(cls, report) -> bytes:
        lines = ["TeamSyncPro Report"]
        rtype = report.get("report_type")
        if rtype is not None:
            lines.append("Type: {0}".format(rtype))
        rows = report.get("rows")
        if isinstance(rows, list):
            for row in rows:
                lines.append(cls._stringify(row))
        else:
            for key, value in report.items():
                lines.append("{0}: {1}".format(key, cls._stringify(value)))
        return _build_pdf(lines)


def _build_pdf(lines) -> bytes:
    """Build a minimal, structurally valid single-page PDF document."""

    def esc(text):
        return (
            str(text)
            .replace("\\", "\\\\")
            .replace("(", "\\(")
            .replace(")", "\\)")
        )

    content_parts = ["BT", "/F1 12 Tf", "50 750 Td", "14 TL"]
    for index, line in enumerate(lines or [""]):
        if index:
            content_parts.append("T*")
        content_parts.append("({0}) Tj".format(esc(line)))
    content_parts.append("ET")
    stream = "\n".join(content_parts).encode("latin-1", "replace")

    objects = [
        b"<< /Type /Catalog /Pages 2 0 R >>",
        b"<< /Type /Pages /Kids [3 0 R] /Count 1 >>",
        (
            b"<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
            b"/Resources << /Font << /F1 5 0 R >> >> /Contents 4 0 R >>"
        ),
        b"<< /Length " + str(len(stream)).encode("ascii") + b" >>\nstream\n"
        + stream + b"\nendstream",
        b"<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>",
    ]

    pdf = bytearray(b"%PDF-1.4\n")
    offsets = []
    for number, obj in enumerate(objects, start=1):
        offsets.append(len(pdf))
        pdf += "{0} 0 obj\n".format(number).encode("ascii")
        pdf += obj
        pdf += b"\nendobj\n"

    xref_pos = len(pdf)
    size = len(objects) + 1
    pdf += "xref\n0 {0}\n".format(size).encode("ascii")
    pdf += b"0000000000 65535 f \n"
    for offset in offsets:
        pdf += "{0:010d} 00000 n \n".format(offset).encode("ascii")
    pdf += (
        "trailer\n<< /Size {0} /Root 1 0 R >>\nstartxref\n{1}\n%%EOF\n"
        .format(size, xref_pos)
        .encode("ascii")
    )
    return bytes(pdf)


