class TeamCollaborationManager:
    """The public entry point that ties every sub-manager together.

    All sub-managers share a single re-entrant lock (exposed as ``_lock`` on
    the manager and on every sub-manager) so that operations that span more
    than one collection remain atomic and the whole system is safe for
    concurrent use.
    """

    def __init__(self, now=None):
        self._state = _State(now)
        self._lock = self._state.lock

        self.users = _UserManager(self._state)
        self.projects = _ProjectManager(self._state)
        self.tasks = _TaskManager(self._state)
        self.messages = _MessageManager(self._state)
        self.performance = _PerformanceManager(self._state)
        self.reports = _ReportManager(self._state)

